#include <iostream>
#include <iomanip>

class Time {
private:
    int hour;
    int minute;
    int second;

public:
    Time() : hour(0), minute(0), second(0) {}

    void setHour(int h) {
        if (h >= 0 && h <= 23) {
            hour = h;
        } else {
            std::cerr << "Invalid hour: " << h << ". Hour not set." << std::endl;
        }
    }

    void setMinute(int m) {
        if (m >= 0 && m <= 59) { // Correct validation
            minute = m;
        } else {
            std::cerr << "Invalid minute: " << m << ". Minute not set." << std::endl;
        }
    }

    void setSecond(int s) {
        if (s >= 0 && s <= 59) {
            second = s;
        } else {
            std::cerr << "Invalid second: " << s << ". Second not set." << std::endl;
        }
    }

    void displayTime() const {
        std::cout << std::setw(2) << std::setfill('0') << hour << ":"
                  << std::setw(2) << std::setfill('0') << minute << ":"
                  << std::setw(2) << std::setfill('0') << second << std::endl;
    }
};

int main() {
    Time t;
    std::cout << "Initial time: ";
    t.displayTime();

    t.setHour(10);
    t.setMinute(30);
    t.setSecond(45);
    std::cout << "Set to 10:30:45: ";
    t.displayTime();

    t.setMinute(60); // This should be invalid
    std::cout << "Attempting to set minute to 60: ";
    t.displayTime();

    t.setHour(23);
    t.setMinute(59);
    t.setSecond(59);
    std::cout << "Set to 23:59:59: ";
    t.displayTime();

    t.setHour(24); // Invalid
    t.setMinute(-1); // Invalid
    t.setSecond(60); // Invalid
    std::cout << "Attempting invalid settings (non-60): ";
    t.displayTime();

    return 0;
}
